func (mmUpdatePanorama *mContentMockUpdatePanorama) Times(n uint64) *mContentMockUpdatePanorama {
	if n == 0 {
		mmUpdatePanorama.mock.t.Fatalf("Times of ContentMock.UpdatePanorama mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmUpdatePanorama.expectedInvocations, n)
	mmUpdatePanorama.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmUpdatePanorama
}

func (mmUpdatePanorama *mContentMockUpdatePanorama) invocationsDone() bool {
	if len(mmUpdatePanorama.expectations) == 0 && mmUpdatePanorama.defaultExpectation == nil && mmUpdatePanorama.mock.funcUpdatePanorama == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmUpdatePanorama.mock.afterUpdatePanoramaCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmUpdatePanorama.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// UpdatePanorama implements mm_service.Content
func (mmUpdatePanorama *ContentMock) UpdatePanorama(ctx context.Context, p domain.Panorama) (p1 domain.Panorama, err error) {
	mm_atomic.AddUint64(&mmUpdatePanorama.beforeUpdatePanoramaCounter, 1)
	defer mm_atomic.AddUint64(&mmUpdatePanorama.afterUpdatePanoramaCounter, 1)

	mmUpdatePanorama.t.Helper()

	if mmUpdatePanorama.inspectFuncUpdatePanorama != nil {
		mmUpdatePanorama.inspectFuncUpdatePanorama(ctx, p)
	}

	mm_params := ContentMockUpdatePanoramaParams{ctx, p}

	// Record call args
	mmUpdatePanorama.UpdatePanoramaMock.mutex.Lock()
	mmUpdatePanorama.UpdatePanoramaMock.callArgs = append(mmUpdatePanorama.UpdatePanoramaMock.callArgs, &mm_params)
	mmUpdatePanorama.UpdatePanoramaMock.mutex.Unlock()

	for _, e := range mmUpdatePanorama.UpdatePanoramaMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.p1, e.results.err
		}
	}

	if mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.Counter, 1)
		mm_want := mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.params
		mm_want_ptrs := mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.paramPtrs

		mm_got := ContentMockUpdatePanoramaParams{ctx, p}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmUpdatePanorama.t.Errorf("ContentMock.UpdatePanorama got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

			if mm_want_ptrs.p != nil && !minimock.Equal(*mm_want_ptrs.p, mm_got.p) {
				mmUpdatePanorama.t.Errorf("ContentMock.UpdatePanorama got unexpected parameter p, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.expectationOrigins.originP, *mm_want_ptrs.p, mm_got.p, minimock.Diff(*mm_want_ptrs.p, mm_got.p))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmUpdatePanorama.t.Errorf("ContentMock.UpdatePanorama got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmUpdatePanorama.UpdatePanoramaMock.defaultExpectation.results
		if mm_results == nil {
			mmUpdatePanorama.t.Fatal("No results are set for the ContentMock.UpdatePanorama")
		}
		return (*mm_results).p1, (*mm_results).err
	}
	if mmUpdatePanorama.funcUpdatePanorama != nil {
		return mmUpdatePanorama.funcUpdatePanorama(ctx, p)
	}
	mmUpdatePanorama.t.Fatalf("Unexpected call to ContentMock.UpdatePanorama. %v %v", ctx, p)
	return
}

// UpdatePanoramaAfterCounter returns a count of finished ContentMock.UpdatePanorama invocations
func (mmUpdatePanorama *ContentMock) UpdatePanoramaAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdatePanorama.afterUpdatePanoramaCounter)
}

// UpdatePanoramaBeforeCounter returns a count of ContentMock.UpdatePanorama invocations
func (mmUpdatePanorama *ContentMock) UpdatePanoramaBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmUpdatePanorama.beforeUpdatePanoramaCounter)
}

// Calls returns a list of arguments used in each call to ContentMock.UpdatePanorama.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmUpdatePanorama *mContentMockUpdatePanorama) Calls() []*ContentMockUpdatePanoramaParams {
	mmUpdatePanorama.mutex.RLock()

	argCopy := make([]*ContentMockUpdatePanoramaParams, len(mmUpdatePanorama.callArgs))
	copy(argCopy, mmUpdatePanorama.callArgs)

	mmUpdatePanorama.mutex.RUnlock()

	return argCopy
}

// MinimockUpdatePanoramaDone returns true if the count of the UpdatePanorama invocations corresponds
// the number of defined expectations
func (m *ContentMock) MinimockUpdatePanoramaDone() bool {
	if m.UpdatePanoramaMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.UpdatePanoramaMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.UpdatePanoramaMock.invocationsDone()
}

// MinimockUpdatePanoramaInspect logs each unmet expectation
func (m *ContentMock) MinimockUpdatePanoramaInspect() {
	for _, e := range m.UpdatePanoramaMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to ContentMock.UpdatePanorama at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterUpdatePanoramaCounter := mm_atomic.LoadUint64(&m.afterUpdatePanoramaCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.UpdatePanoramaMock.defaultExpectation != nil && afterUpdatePanoramaCounter < 1 {
		if m.UpdatePanoramaMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to ContentMock.UpdatePanorama at\n%s", m.UpdatePanoramaMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to ContentMock.UpdatePanorama at\n%s with params: %#v", m.UpdatePanoramaMock.defaultExpectation.expectationOrigins.origin, *m.UpdatePanoramaMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcUpdatePanorama != nil && afterUpdatePanoramaCounter < 1 {
		m.t.Errorf("Expected call to ContentMock.UpdatePanorama at\n%s", m.funcUpdatePanoramaOrigin)
	}

	if !m.UpdatePanoramaMock.invocationsDone() && afterUpdatePanoramaCounter > 0 {
		m.t.Errorf("Expected %d calls to ContentMock.UpdatePanorama at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.UpdatePanoramaMock.expectedInvocations), m.UpdatePanoramaMock.expectedInvocationsOrigin, afterUpdatePanoramaCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *ContentMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockCreateDocumentInspect()

			m.MinimockCreatePanoramaInspect()

			m.MinimockDeleteDocumentInspect()

			m.MinimockDeletePanoramaInspect()

			m.MinimockListDocumentsInspect()

			m.MinimockListPanoramasInspect()

			m.MinimockUpdatePanoramaInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *ContentMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *ContentMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockCreateDocumentDone() &&
		m.MinimockCreatePanoramaDone() &&
		m.MinimockDeleteDocumentDone() &&
		m.MinimockDeletePanoramaDone() &&
		m.MinimockListDocumentsDone() &&
		m.MinimockListPanoramasDone() &&
		m.MinimockUpdatePanoramaDone()
}
